import{_ as e,o,c as a,a2 as t}from"./chunks/framework.DvFsUg-r.js";const h=JSON.parse('{"title":"spec→blog 동기화가 잡아낸 잠복 버그 — MDX는 < 다음 숫자를 태그로 본다","description":"","frontmatter":{"slug":"spec-sync-mdx-pitfall","title":"spec→blog 동기화가 잡아낸 잠복 버그 — MDX는 `<` 다음 숫자를 태그로 본다","authors":[],"tags":["docusaurus","mdx","spec-kit","sdd","ci","troubleshooting"],"created":"2026-05-31 15:40 (KST)","date":"2026-05-31T06:40:00.000Z"},"headers":[],"relativePath":"journal/2026-05-31-spec-sync-mdx-pitfall.md","filePath":"journal/2026-05-31-spec-sync-mdx-pitfall.md","lastUpdated":1781092690000}'),c={name:"journal/2026-05-31-spec-sync-mdx-pitfall.md"};function d(n,s,l,i,p,r){return o(),a("div",null,[...s[0]||(s[0]=[t('<p>feature 004 를 마감하고 <code>status: done</code> 까지 올린 뒤, <code>scripts/sync-specs-to-blog.sh</code> 를 돌렸다. 별일 없을 동기화라 생각했는데, 직후 빌드가 <strong>MDX 파싱 에러</strong>로 죽었다. 원인은 한 글자 — <code>&lt;</code> 였다. CI 배포에서 터졌을 잠복 버그를 동기화가 먼저 잡아준 셈이라 기록으로 남긴다.</p><h2 id="증상" tabindex="-1">증상 <a class="header-anchor" href="#증상" aria-label="Permalink to &quot;증상&quot;">​</a></h2><p><code>bash scripts/sync-specs-to-blog.sh</code> 는 조용히 성공했다(<code>synced 17 spec file(s)</code>). 그런데 이어서 <code>npx docusaurus build</code> 가 이렇게 터졌다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>× MDX compilation failed for &quot;blog/docs/004-platform-admin-migration/quickstart.md&quot;</span></span>\n<span class="line"><span>  Cause: Unexpected character `3` (U+0033) before name,</span></span>\n<span class="line"><span>         expected a character that can start a name, such as a letter, `$`, or `_`</span></span></code></pre></div><p><code>tasks.md</code> 도 같은 이유로 동반 실패. 범인은 Phase 10 문서에 무심코 쓴 표기였다:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">3,000건 기간 검색 &lt;3초 (SC-4 …)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">… | ✅ &lt;3s |</span></span></code></pre></div><p>Docusaurus 3 의 MDX 는 <code>&lt;</code> 를 만나면 <strong>JSX 태그 시작</strong>으로 본다. 그런데 태그 이름은 글자·<code>$</code>·<code>_</code> 로만 시작할 수 있어서, <code>&lt;3</code> 의 숫자 <code>3</code> 에서 파서가 멈춘다. 즉 &quot;3초 미만&quot;을 줄이려고 쓴 <code>&lt;3초</code> 가 <code>&lt;3초&gt;</code> 같은 가짜 태그로 해석된 것이다.</p><h2 id="왜-바로-직전-빌드는-통과했나-핵심" tabindex="-1">왜 바로 직전 빌드는 통과했나 (핵심) <a class="header-anchor" href="#왜-바로-직전-빌드는-통과했나-핵심" aria-label="Permalink to &quot;왜 바로 직전 빌드는 통과했나 (핵심)&quot;">​</a></h2><p>이게 헷갈리는 지점이었다. 마감 단계(T080)에서 분명히 <code>docusaurus build</code> 가 <strong>SUCCESS</strong> 였는데, 같은 파일이 지금 와서 깨진다.</p><p>답은 <strong>빌드가 읽는 대상</strong>에 있다. 파이프라인은 두 단계다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>specs/**/*.md  ──(sync-specs-to-blog.sh)──&gt;  blog/docs/  ──(docusaurus build)──&gt;  정적 사이트</span></span></code></pre></div><ul><li><code>docusaurus build</code> 는 <code>specs/</code> 가 아니라 <strong>동기화본 <code>blog/docs/</code></strong> 를 읽는다.</li><li><code>blog/docs/</code> 는 <code>.gitignore</code> 대상(= 생성물)이라, 내가 <code>specs/</code> 를 고쳐도 <strong>sync 를 돌리기 전까지는 <code>blog/docs/</code> 가 옛 내용</strong> 그대로다.</li></ul><p>그래서 T080 빌드는 <code>&lt;3초</code> 가 <strong>아직 동기화되지 않은</strong> 옛 docs 를 읽어 통과했고, 이번에 sync 를 돌리자 비로소 새 내용이 <code>blog/docs/</code> 에 반영되며 깨졌다. GitHub Actions 는 <code>sync → build → deploy</code> 를 한 번에 하므로, 이대로 push 했으면 <strong>배포가 실패</strong>했을 것이다. &quot;로컬 빌드 초록&quot;이 &quot;CI 빌드 초록&quot;을 보장하지 못한 전형적인 케이스다.</p><h2 id="고침" tabindex="-1">고침 <a class="header-anchor" href="#고침" aria-label="Permalink to &quot;고침&quot;">​</a></h2><p>소스(<code>specs/</code>)에서 <code>&lt;</code> 를 없앴다. 표현만 바꾸면 된다:</p><div class="language-diff vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">diff</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">- 3,000건 기간 검색 &lt;3초 (SC-4 …)</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ 3,000건 기간 검색 3초 미만 (SC-4 …)</span></span>\n<span class="line"><span style="--shiki-light:#B31D28;--shiki-dark:#FDAEB7;">- … | ✅ &lt;3s |</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">+ … | ✅ 3s 미만 |</span></span></code></pre></div><p>그리고 <strong>sync 를 다시 돌린 뒤 build</strong> → SUCCESS. <code>blog/docs/</code> 는 생성물이라 커밋하지 않고, 고친 건 소스 spec 두 파일뿐이다.</p><h2 id="남길-교훈" tabindex="-1">남길 교훈 <a class="header-anchor" href="#남길-교훈" aria-label="Permalink to &quot;남길 교훈&quot;">​</a></h2><ol><li><strong><code>&lt;</code> 다음에 글자가 아니면 MDX 에서 escape 하거나 표현을 바꾼다.</strong> <code>&lt;3</code>, <code>&lt;=</code>, <code>a&lt;b</code>, <code>List&lt;T&gt;</code> 같은 표기가 흔한 지뢰다. 백틱 인라인 코드(<code>`&lt;3초`</code>)로 감싸도 안전하다.</li><li><strong>생성물 디렉터리(<code>blog/docs/</code>)를 읽는 빌드는, 생성 단계를 먼저 돌리지 않으면 거짓 초록을 준다.</strong> 문서 회귀를 확인할 땐 <code>sync → build</code> 를 한 묶음으로 돌려야 CI 와 같은 그림을 본다.</li><li>CLAUDE.md 가 &quot;저널/스펙 수정 후 <code>docusaurus build</code> 로 파싱 확인&quot;을 요구하는 이유가 이거다 — 다만 <strong>sync 까지 포함해야</strong> 의미가 있다.</li></ol>',19)])])}const g=e(c,[["render",d]]);export{h as __pageData,g as default};
